# Implement find_nth occurrence
def find_nth(haystack, needle, n):
    # n starting at 1, find nth occurrence
    index = -1
    start = 0
    for i in range(n):
        idx = haystack.find(needle, start)
        if idx == -1:
            return -1
        index = idx
        start = idx + 1
    return index

